```javascript
// Example GET request
fetch('https://api.example.com/data')
  .then(response => {
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    return response.json(); // Parse JSON response
  })
  .then(data => {
    console.log(data); // Handle the data here
  })
  .catch(error => {
    console.error('There was an error!', error);
  });
```

